using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public sealed class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public sealed class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketModelTrainer
{
    private readonly MLContext _mlContext = new(seed: 42);
    private readonly ILogger<TicketModelTrainer> _logger;

    public TicketModelTrainer(ILogger<TicketModelTrainer> logger)
    {
        _logger = logger;
    }

    public string TrainAndSave(string dataPath, string modelPath)
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

        var pipeline = _mlContext.Transforms.Text
            .FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject))
            .Append(_mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training ticket classifier model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        var report = $"""
            === Ticket Classifier Evaluation ===
            Macro Accuracy:    {metrics.MacroAccuracy:F4}
            Micro Accuracy:    {metrics.MicroAccuracy:F4}
            Log Loss:          {metrics.LogLoss:F4}
            Log Loss Reduction:{metrics.LogLossReduction:F4}
            """;

        _logger.LogInformation(report);

        _mlContext.Model.Save(model, dataView.Schema, modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", modelPath);

        return report;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;

    public TicketClassifierController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPrediction> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject))
            return BadRequest("Subject is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description ?? string.Empty,
            Priority = request.Priority,
        };

        var prediction = _predictionPool.Predict(input);
        return Ok(prediction);
    }
}

